"""Plot results generated by mswd-acc.py.

Default input:
    results/mswd_acc_results.csv

Default output directory:
    images/
"""

import argparse
import csv
import math
import os
from collections import defaultdict

import matplotlib.pyplot as plt


GROUP_COLUMNS = ["model", "n1", "n2", "sample_dim", "variant"]
METHODS = [
    {
        "name": "L0-MSWD",
        "prefix": "l0",
        "color": "#2f6f9f",
    },
    {
        "name": "L1-MSWD",
        "prefix": "l1",
        "color": "#b04a5a",
    },
]


def _to_float(value):
    if value is None or value == "":
        return None
    try:
        parsed = float(value)
    except ValueError:
        return None
    if math.isnan(parsed):
        return None
    return parsed


def _to_int(value):
    parsed = _to_float(value)
    if parsed is None:
        return None
    return int(parsed)


def _safe_name(text):
    keep = []
    for char in str(text):
        if char.isalnum() or char in ("-", "_"):
            keep.append(char)
        else:
            keep.append("_")
    return "".join(keep).strip("_")


def _read_rows(path):
    with open(path, newline="", encoding="utf-8") as handle:
        reader = csv.DictReader(handle)
        return list(reader)


def _group_rows(rows):
    groups = defaultdict(list)
    for row in rows:
        key = tuple(row.get(column, "") for column in GROUP_COLUMNS)
        groups[key].append(row)
    for key in groups:
        groups[key].sort(key=lambda row: _to_int(row.get("run")) or 0)
    return groups


def _group_title(key):
    values = dict(zip(GROUP_COLUMNS, key))
    return (
        f"{values['model']}, n1={values['n1']}, n2={values['n2']}, "
        f"dim={values['sample_dim']}, {values['variant']}"
    )


def _group_slug(key):
    values = dict(zip(GROUP_COLUMNS, key))
    return _safe_name(
        f"{values['model']}_n1{values['n1']}_n2{values['n2']}_"
        f"d{values['sample_dim']}_{values['variant']}"
    )


def _available_methods(rows):
    available = []
    for method in METHODS:
        prefix = method["prefix"]
        if any(_to_float(row.get(f"{prefix}_stat")) is not None for row in rows):
            available.append(method)
    return available


def plot_rejection_curve(rows, title, out_path):
    methods = _available_methods(rows)
    if not methods:
        return False

    fig, ax = plt.subplots(figsize=(8.5, 5.0), dpi=160)
    for method in methods:
        prefix = method["prefix"]
        xs = []
        ys = []
        for index, row in enumerate(rows):
            rate = _to_float(row.get(f"{prefix}_rej_rate"))
            if rate is None:
                continue
            xs.append((_to_int(row.get("run")) or index) + 1)
            ys.append(rate)
        if xs:
            ax.plot(xs, ys, color=method["color"], linewidth=2.2, label=method["name"])

    ax.set_title(f"MSWD Rejection Rate\n{title}", fontsize=11)
    ax.set_xlabel("Monte Carlo run")
    ax.set_ylabel("Cumulative rejection rate")
    ax.set_ylim(-0.02, 1.02)
    ax.grid(True, color="#d9d9d9", linewidth=0.7, alpha=0.8)
    ax.legend(frameon=False)
    fig.tight_layout()
    fig.savefig(out_path)
    plt.close(fig)
    return True


def plot_stat_threshold(rows, title, out_path):
    methods = _available_methods(rows)
    if not methods:
        return False

    ncols = len(methods)
    fig, axes = plt.subplots(1, ncols, figsize=(8.5 * ncols, 5.0), dpi=160, squeeze=False)
    for ax, method in zip(axes[0], methods):
        prefix = method["prefix"]
        xs = []
        stats = []
        threshes = []
        for index, row in enumerate(rows):
            stat = _to_float(row.get(f"{prefix}_stat"))
            thresh = _to_float(row.get(f"{prefix}_thresh"))
            if stat is None:
                continue
            xs.append((_to_int(row.get("run")) or index) + 1)
            stats.append(stat)
            threshes.append(thresh)

        ax.plot(xs, stats, color=method["color"], linewidth=1.8, label="Statistic")
        if any(value is not None for value in threshes):
            valid_x = [x for x, y in zip(xs, threshes) if y is not None]
            valid_y = [y for y in threshes if y is not None]
            ax.plot(valid_x, valid_y, color="#333333", linewidth=1.5, linestyle="--", label="Threshold")
        ax.set_title(method["name"], fontsize=11)
        ax.set_xlabel("Monte Carlo run")
        ax.set_ylabel("Value")
        ax.grid(True, color="#d9d9d9", linewidth=0.7, alpha=0.8)
        ax.legend(frameon=False)

    fig.suptitle(f"Statistic vs Bootstrap Threshold\n{title}", fontsize=12)
    fig.tight_layout()
    fig.savefig(out_path)
    plt.close(fig)
    return True


def plot_elapsed(rows, title, out_path):
    xs = []
    ys = []
    for index, row in enumerate(rows):
        elapsed = _to_float(row.get("elapsed_sec"))
        if elapsed is None:
            continue
        xs.append((_to_int(row.get("run")) or index) + 1)
        ys.append(elapsed)
    if not xs:
        return False

    fig, ax = plt.subplots(figsize=(8.5, 4.6), dpi=160)
    ax.plot(xs, ys, color="#4f6b3a", linewidth=1.8)
    ax.axhline(sum(ys) / len(ys), color="#333333", linewidth=1.3, linestyle="--", label="Mean")
    ax.set_title(f"Runtime Per Run\n{title}", fontsize=11)
    ax.set_xlabel("Monte Carlo run")
    ax.set_ylabel("Seconds")
    ax.grid(True, color="#d9d9d9", linewidth=0.7, alpha=0.8)
    ax.legend(frameon=False)
    fig.tight_layout()
    fig.savefig(out_path)
    plt.close(fig)
    return True


def plot_final_summary(groups, out_path):
    labels = []
    l0_values = []
    l1_values = []
    for key, rows in groups.items():
        labels.append(_group_slug(key))
        last = rows[-1]
        l0_values.append(_to_float(last.get("l0_rej_rate")))
        l1_values.append(_to_float(last.get("l1_rej_rate")))

    if not labels:
        return False

    width = 0.36
    xs = list(range(len(labels)))
    fig, ax = plt.subplots(figsize=(max(8.5, 1.4 * len(labels)), 5.0), dpi=160)
    has_l0 = any(value is not None for value in l0_values)
    has_l1 = any(value is not None for value in l1_values)
    if has_l0:
        ax.bar([x - width / 2 for x in xs], [value or 0 for value in l0_values], width, color="#2f6f9f", label="L0-MSWD")
    if has_l1:
        ax.bar([x + width / 2 for x in xs], [value or 0 for value in l1_values], width, color="#b04a5a", label="L1-MSWD")
    ax.set_title("Final MSWD Rejection Rate", fontsize=12)
    ax.set_ylabel("Rejection rate")
    ax.set_ylim(0, 1.02)
    ax.set_xticks(xs)
    ax.set_xticklabels(labels, rotation=35, ha="right", fontsize=8)
    ax.grid(True, axis="y", color="#d9d9d9", linewidth=0.7, alpha=0.8)
    ax.legend(frameon=False)
    fig.tight_layout()
    fig.savefig(out_path)
    plt.close(fig)
    return True


def parse_args():
    parser = argparse.ArgumentParser(description="Plot mswd-acc.py CSV results.")
    parser.add_argument("--input", default="results/mswd_acc_results.csv", type=str)
    parser.add_argument("--outdir", default="images", type=str)
    return parser.parse_args()


def main():
    args = parse_args()
    os.makedirs(args.outdir, exist_ok=True)
    rows = _read_rows(args.input)
    if not rows:
        raise RuntimeError(f"No rows found in {args.input}")

    groups = _group_rows(rows)
    written = []
    for key, group_rows in groups.items():
        slug = _group_slug(key)
        title = _group_title(key)
        targets = [
            (plot_rejection_curve, os.path.join(args.outdir, f"{slug}_rejection_curve.png")),
            (plot_stat_threshold, os.path.join(args.outdir, f"{slug}_stat_threshold.png")),
            (plot_elapsed, os.path.join(args.outdir, f"{slug}_runtime.png")),
        ]
        for plotter, path in targets:
            if plotter(group_rows, title, path):
                written.append(path)

    summary_path = os.path.join(args.outdir, "mswd_final_summary.png")
    if plot_final_summary(groups, summary_path):
        written.append(summary_path)

    print("Saved images:")
    for path in written:
        print(path)


if __name__ == "__main__":
    main()
